(window.webpackJsonp=window.webpackJsonp||[]).push([[433],{461:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">N</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">lamps</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">queries</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> gridIllumination = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">N, lamps, queries</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> row={},col={},rdSlash={},ltSlash={}\\n  <span class=\\"hljs-keyword\\">let</span> lampHash=<span class=\\"hljs-keyword\\">new</span> <span class=\\"hljs-built_in\\">Map</span>()\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;lamps.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [x,y]=lamps[i]\\n    lampHash.set(x+<span class=\\"hljs-string\\">\'-\'</span>+y,<span class=\\"hljs-literal\\">true</span>)\\n    <span class=\\"hljs-keyword\\">let</span> ltSy=y-x\\n    <span class=\\"hljs-keyword\\">let</span> rdSx=x+y\\n    <span class=\\"hljs-keyword\\">if</span>(row[x]==<span class=\\"hljs-literal\\">null</span>)row[x]=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">else</span> row[x]++\\n    <span class=\\"hljs-keyword\\">if</span>(col[y]==<span class=\\"hljs-literal\\">null</span>)col[y]=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">else</span> col[y]++\\n    <span class=\\"hljs-keyword\\">if</span>(rdSlash[rdSx]==<span class=\\"hljs-literal\\">null</span>)rdSlash[rdSx]=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">else</span> rdSlash[rdSx]++\\n    <span class=\\"hljs-keyword\\">if</span>(ltSlash[ltSy]==<span class=\\"hljs-literal\\">null</span>)ltSlash[ltSy]=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">else</span> ltSlash[ltSy]++\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">checkSurr</span>(<span class=\\"hljs-params\\">[x,y]</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> d=[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">-1</span>]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> dx <span class=\\"hljs-keyword\\">of</span> d){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> dy <span class=\\"hljs-keyword\\">of</span> d){\\n        <span class=\\"hljs-keyword\\">let</span> newx=x+dx,newy=y+dy\\n        <span class=\\"hljs-keyword\\">if</span>(newx&lt;<span class=\\"hljs-number\\">0</span> || newy&lt;<span class=\\"hljs-number\\">0</span> || newx&gt;=N || newy&gt;=N)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">if</span>(lampHash.has(newx+<span class=\\"hljs-string\\">\'-\'</span>+newy)){\\n          lampHash.delete(newx+<span class=\\"hljs-string\\">\'-\'</span>+newy)\\n          <span class=\\"hljs-keyword\\">let</span> r=newx,c=newy,lt=newy-newx,rd=newx+newy\\n          row[r]--\\n          col[c]--\\n          rdSlash[rd]--\\n          ltSlash[lt]--\\n        }\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-comment\\">// console.log()</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">checkIsLight</span>(<span class=\\"hljs-params\\">[x,y]</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> r=x,c=y,lt=y-x,rd=x+y\\n    <span class=\\"hljs-keyword\\">let</span> isLight=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">if</span>(row[r]&gt;<span class=\\"hljs-number\\">0</span>||col[c]&gt;<span class=\\"hljs-number\\">0</span>||rdSlash[rd]&gt;<span class=\\"hljs-number\\">0</span>||ltSlash[lt]&gt;<span class=\\"hljs-number\\">0</span>)isLight=<span class=\\"hljs-number\\">1</span>\\n    checkSurr([x,y])\\n    <span class=\\"hljs-comment\\">// console.log(isLight)</span>\\n    <span class=\\"hljs-keyword\\">return</span> isLight\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> result=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;queries.length;i++){\\n    result.push(checkIsLight(queries[i]))\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> result\\n};\\n</code></pre>\\n"],"titleSlug":"grid-illumination","hasThinking":false,"content":"<p>\u5728\xa0<code>N x N</code>\xa0\u7684\u7f51\u683c <code>grid</code> \u4e0a\uff0c\u6bcf\u4e2a\u5355\u5143\u683c\u90fd\u6709\u4e00\u76cf\u706f\uff0c\u6700\u521d\u706f\u90fd\u5904\u4e8e <strong>\u5173\u95ed</strong> \u72b6\u6001\u3002</p>\\n\\n<p>\u6570\u7ec4\xa0<code>lamps</code> \u8868\u793a\u6253\u5f00\u7684\u706f\u7684\u4f4d\u7f6e\u3002<code>lamps[i] = [row<sub>i</sub>, col<sub>i</sub>]</code> \u8868\u793a <strong>\u6253\u5f00</strong> \u4f4d\u4e8e <code>grid[row<sub>i</sub>][col<sub>i</sub>]</code> \u7684\u7b2c <code>i</code> \u76cf\u706f \u3002\u6bcf\u76cf\u706f\u90fd\u7167\u4eae\u81ea\u8eab\u5355\u5143\u683c\u4ee5\u53ca\u540c\u4e00\u884c\u3001\u540c\u4e00\u5217\u548c\u4e24\u6761\u5bf9\u89d2\u7ebf\u4e0a\u7684\u6240\u6709\u5176\u4ed6\u5355\u5143\u683c\u3002</p>\\n\\n<p>\u67e5\u8be2\u6570\u7ec4 <code>queries</code> \u4e2d\uff0c\u7b2c <code>i</code> \u6b21\u67e5\u8be2\xa0<code>queries[i] = [row<sub>i</sub>, col<sub>i</sub>]</code>\uff0c\u5982\u679c\u5355\u5143\u683c <code>[row<sub>i</sub>, col<sub>i</sub>]</code> \u662f\u88ab\u7167\u4eae\u7684\uff0c\u5219\u67e5\u8be2\u7ed3\u679c\u4e3a <code>1</code> \uff0c\u5426\u5219\u4e3a <code>0</code> \u3002\u5728\u7b2c <code>i</code> \u6b21\u67e5\u8be2\u4e4b\u540e [\u6309\u7167\u67e5\u8be2\u7684\u987a\u5e8f] \uff0c<strong>\u5173\u95ed</strong> \u4f4d\u4e8e\u5355\u5143\u683c <code>grid[row<sub>i</sub>][col<sub>i</sub>]</code> \u4e0a\u6216\u5176\u76f8\u90bb 8 \u4e2a\u65b9\u5411\u4e0a\uff08\u4e0e\u5355\u5143\u683c <code>grid[row<sub>i</sub>][col<sub>i</sub>]</code> \u5171\u4eab\u89d2\u6216\u8fb9\uff09\u7684\u4efb\u4f55\u706f\u3002</p>\\n\\n<p>\u8fd4\u56de\u7b54\u6848\u6570\u7ec4 <code>ans</code> \uff0c <code>answer[i]</code> \u5e94\u7b49\u4e8e\u7b2c <code>i</code>\xa0\u6b21\u67e5\u8be2\xa0<code>queries[i]</code>\xa0\u7684\u7ed3\u679c\uff0c<code>1</code> \u8868\u793a\u7167\u4eae\uff0c<code>0</code> \u8868\u793a\u672a\u7167\u4eae\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/08/19/illu_1.jpg\\" style=\\"width: 750px; height: 209px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>N = 5, lamps = [[0,0],[4,4]], queries = [[1,1],[1,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,0]\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u521d\u6240\u6709\u706f\u90fd\u662f\u5173\u95ed\u7684\u3002\u5728\u6267\u884c\u67e5\u8be2\u4e4b\u524d\uff0c\u6253\u5f00\u4f4d\u4e8e [0, 0] \u548c [4, 4] \u7684\u706f\u3002\u7b2c 0\xa0\u6b21\u67e5\u8be2\u68c0\u67e5 grid[1][1] \u662f\u5426\u88ab\u7167\u4eae\uff08\u84dd\u8272\u65b9\u6846\uff09\u3002\u8be5\u5355\u5143\u683c\u88ab\u7167\u4eae\uff0c\u6240\u4ee5 ans[0] = 1 \u3002\u7136\u540e\uff0c\u5173\u95ed\u7ea2\u8272\u65b9\u6846\u4e2d\u7684\u6240\u6709\u706f\u3002\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/08/19/illu_step1.jpg\\" style=\\"width: 500px; height: 218px;\\" />\\n\u7b2c 1\xa0\u6b21\u67e5\u8be2\u68c0\u67e5 grid[1][0] \u662f\u5426\u88ab\u7167\u4eae\uff08\u84dd\u8272\u65b9\u6846\uff09\u3002\u8be5\u5355\u5143\u683c\u6ca1\u6709\u88ab\u7167\u4eae\uff0c\u6240\u4ee5 ans[1] = 0 \u3002\u7136\u540e\uff0c\u5173\u95ed\u7ea2\u8272\u77e9\u5f62\u4e2d\u7684\u6240\u6709\u706f\u3002\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/08/19/illu_step2.jpg\\" style=\\"width: 500px; height: 219px;\\" />\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>N = 5, lamps = [[0,0],[4,4]], queries = [[1,1],[1,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>N = 5, lamps = [[0,0],[0,4]], queries = [[0,4],[0,1],[1,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,1,0]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= N <= 10<sup>9</sup></code></li>\\n\\t<li><code>0 <= lamps.length <= 20000</code></li>\\n\\t<li><code>lamps[i].length == 2</code></li>\\n\\t<li><code>0 <= lamps[i][j] < N</code></li>\\n\\t<li><code>0 <= queries.length <= 20000</code></li>\\n\\t<li><code>queries[i].length == 2</code></li>\\n\\t<li><code>0 <= queries[i][j] < N</code></li>\\n</ul>\\n","title":"1001. \u7f51\u683c\u7167\u660e","relatedTags":["\u54c8\u5e0c\u8868"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1001"}')}}]);